((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='logical-connectives' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which is logically equivalent to P→Q?','¬P∨Q','P∧Q','¬P→¬Q','Q→P','A','P→Q ≡ ¬P∨Q (a conditional is equivalent to the disjunction of not-P or Q).','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='logical-connectives' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''Neither P nor Q' means:','P or Q','P and Q','Not P and not Q','Not P or not Q','C','Neither P nor Q = NOT P AND NOT Q (both are false).','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='logical-connectives' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Sufficient condition: 'P is sufficient for Q' means:','Q is sufficient for P','P→Q','Q→P','P↔Q','B',''P is sufficient for Q' means P→Q (P guarantees Q).','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='logical-connectives' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Necessary condition: 'P is necessary for Q' means:','P→Q','Q→P','P↔Q','¬P→¬Q','B',''P is necessary for Q' means Q cannot happen without P, i.e., Q→P.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='logical-connectives' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'If P→Q is true and Q→P is also true, then:','P and Q are unrelated','P↔Q (P if and only if Q)','P causes Q','Q causes P','B','P→Q and Q→P together give P↔Q (biconditional).','medium',true),
