((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='logical-connectives' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Argument: All A are B. x is B. Therefore x is A. This is:','Valid','Invalid — B does not mean A','Valid by induction','A sound argument','B','Undistributed middle fallacy. Being B does not mean being A.','hard',true),
