((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='grouping-selection' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which best describes a 'sufficient condition' in selection?','The condition may or may not lead to selection','If the condition is met, selection is guaranteed','The condition is required for selection','Selection can happen without the condition','B','Sufficient condition: if it holds, the result follows.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='grouping-selection' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Select a team of 5 from 10. One person refuses to be with another. Valid teams:','C(10,5)-C(8,3)','C(10,5)','C(8,5)','C(8,3)','A','Total C(10,5)=252. Teams with both feuding members: C(8,3)=56. Valid=252-56=196.','hard',true),
