((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='grouping-selection' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'If the rule says 'No two members from the same department' and there are 5 departments with 2 members each, max team size:','5','4','3','10','A','One from each department = maximum 5 members.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='grouping-selection' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''A is necessary for B' means:','A guarantees B','Without A, B cannot happen (B→A)','A and B always occur together','B guarantees A','B','Necessary condition: B requires A → B→A (no A means no B).','hard',true);
