((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'He passed every time he studied. He passed today. Did he study?','Yes definitely','Cannot conclude — other reasons possible','Yes by modus ponens','Only if he always studies','B','Affirming the consequent fallacy: Q being true doesn't prove P.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''After this therefore because of this' describes which fallacy?','Ad hominem','Straw man','Post hoc ergo propter hoc','Slippery slope','C','Post hoc: assuming A caused B just because A preceded B.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which STRENGTHENS 'New pill reduces fever'?','Pill group rested more','Pill group recovered faster than placebo under identical conditions','Fever is uncomfortable','Drugs can have side effects','B','Controlled study with placebo eliminates alternatives — best evidence.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which WEAKENS 'Exercise prevents heart disease'?','Exercise burns calories','Many exercisers still get heart disease due to genetics','Running is best exercise','Doctors recommend exercise','B','If genetics cause heart disease regardless of exercise, exercise alone may not prevent it.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Cause must PRECEDE effect means:','Effect before cause','They are simultaneous','Cause happens BEFORE the effect in time','Any order possible','C','Temporal precedence is a necessary condition for causation.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Cities with more hospitals have more deaths. Best explanation:','Hospitals are dangerous','Ill people go to hospitals so deaths concentrate there','More population = more deaths','Hospitals attract sick people','B','Reverse causation: hospitals don't cause death — the dying go there.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''A study shows students who eat breakfast score higher.' Safest conclusion:','Breakfast definitely causes better scores','Breakfast is associated with better scores','All students should eat breakfast','Breakfast is the only factor','B','Observational studies show association/correlation, not proven causation.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'A confounding variable is:','The main cause','A variable influencing both supposed cause and effect','The effect being measured','The control group','B','Confounders create false impressions of causation.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which is a clear direct causal relationship?','Hot weather and ice cream sales','Striking a match causing a flame','Police presence and crime rates','Tall parents and tall children','B','Striking match → flame has a direct physical mechanism.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'To establish causation scientifically researchers must:','Find a correlation','Use a large survey','Run a controlled experiment with random assignment','Count how often A precedes B','C','Controlled experiments with random assignment are the gold standard for proving causation.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''Rooster crows before sunrise therefore rooster causes sunrise.' This is:','Valid causal reasoning','Post hoc fallacy','Modus ponens','Sound argument','B','Classic post hoc: A before B does not mean A causes B.','easy',true),
