((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Alternative hypothesis in research means:','No relationship exists','The null hypothesis is true','A relationship between variables exists','The experiment failed','C','Alternative hypothesis claims that a relationship/difference exists.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which correctly identifies a cause-effect relationship?','More police → less crime (if proven by controlled study)','Ice cream → drowning','Height → intelligence','Rooster crow → sunrise','A','Only a properly controlled study can establish causal relationships.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Ad hominem fallacy means:','Attacking the argument's logic','Attacking the person making the argument','Using too many premises','Drawing hasty conclusions','B','Ad hominem = attack the person not the argument.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Straw man fallacy means:','Using irrelevant statistics','Misrepresenting someone's argument to attack a weaker version','Appealing to authority','Circular reasoning','B','Straw man: distort opponent's argument then attack the distorted version.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'False dichotomy fallacy presents:','Too many options','Only two options when more exist','No options','Circular reasoning','B','False dichotomy: wrongly claiming there are only two choices.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Circular reasoning (begging the question) is:','A valid argument form','Using the conclusion as a premise to prove the conclusion','An inductive argument','A causal claim','B','Circular: the conclusion is secretly assumed in the premises.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Hasty generalization is drawing a broad conclusion from:','Extensive evidence','Multiple studies','Too small or unrepresentative a sample','Statistical analysis','C','Hasty generalization: generalizing from insufficient or unrepresentative examples.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which statement is a FACT not an opinion?','Chocolate is the best flavour','Pakistan gained independence in 1947','The economy needs reform','Students should work harder','B','Independence in 1947 is a verifiable historical fact.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which STRENGTHENS an argument?','Evidence that confirms the conclusion','Evidence that weakens the conclusion','An unrelated fact','An ad hominem attack','A','Strengtheners support the conclusion with relevant evidence.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which WEAKENS an argument?','Evidence supporting the conclusion','Additional premises','An alternative explanation for the same effect','A stronger version of the argument','C','Alternative explanations weaken causal arguments.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Appeal to authority fallacy is:','Always invalid','Invalid when authority is not relevant to the topic','Always valid','Valid only in science','B','Appeal to authority is fallacious when the cited authority is not an expert in that specific field.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Necessary condition for X means:','X guarantees the condition','Without the condition X cannot happen','The condition is sufficient for X','X and condition always coexist','B','Necessary condition: X requires it (without it, X can't happen).','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='cause-effect' AND level_id=(SELECT id FROM levels WHERE level_no=1 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Sufficient condition for Y means:','Y is required for the condition','Without Y the condition fails','If condition holds then Y must follow','Y is optional','C','Sufficient condition: if it's present, Y is guaranteed.','medium',true),
