((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'An argument's CONCLUSION is:','The evidence provided','The claim the argument proves','Background information','An objection','B','Conclusion = main claim being proven.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Ad hominem fallacy is:','Attacking the argument's logic','Attacking the person not argument','Providing counter-evidence','Asking for clarification','B','Ad hominem = attack the person.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''Some politicians are corrupt. Ali is politician. So Ali is corrupt.' This is:','Valid deductive','Invalid — some ≠ all','Valid inductive','Sound syllogism','B','Some A are B does not mean every A is B.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'STRENGTHENS 'Students who read more perform better':','Reading is enjoyable','Daily readers score 30% higher on standardized tests','Teachers should assign more reading','Some students dislike reading','B','Controlled evidence directly supports the claim.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Assumption in 'Worked in Japan so will work in Pakistan':','Both countries are identical','What works anywhere works everywhere','Pakistan is similar to Japan in relevant ways','The solution is perfect','C','The unstated assumption is that conditions are comparable.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which is a FACTUAL claim?','Chocolate is best','Students should study harder','Pakistan gained independence in 1947','Economy needs reform','C','1947 independence is a verifiable historical fact.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Valid deduction with true premises:','May have false conclusion','Definitely has true conclusion','Has uncertain conclusion','Has no conclusion','B','Valid deduction + true premises = necessarily true conclusion.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Slippery slope fallacy argues:','One step leads inevitably to extreme consequences','Arguments get worse','Facts are relative','People make small mistakes','A','Slippery slope: one action will trigger a chain of extreme events.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'A PREMISE in an argument is:','The final conclusion','Evidence/fact supporting conclusion','Only an assumption','An objection','B','Premises are the supporting evidence.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'WEAKENS 'Banning junk food ads reduces childhood obesity':','Junk food is unhealthy','Children see more ads online (unaffected by ban)','Obesity is growing','Schools should teach nutrition','B','If ads continue online, the ban won't reduce exposure.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which identifies the MAIN CONCLUSION of 'Exercise improves health because it strengthens the heart and reduces stress'?','Strengthens heart','Reduces stress','Exercise improves health','Exercise is important','C',''Exercise improves health' is the main claim being argued.','easy',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),''All swans I have seen are white, so all swans are white.' This is:','Valid deductive reasoning','Inductive reasoning (may be wrong)','A proven fact','A tautology','B','Inductive generalization — can be refuted (black swans exist!).','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which is a VALID argument?','All A are B. x is B. So x is A.','All A are B. x is A. So x is B.','Some A are B. So all A are B.','No A is B. Some C are B. So no C is A.','B','Valid syllogism: All A are B + x is A → x is B (modus ponens).','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'False analogy fallacy occurs when:','Two things are compared despite being relevantly different','Two things are identical','The comparison is accurate','The analogy is helpful','A','False analogy: comparing things that seem similar but have crucial differences.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Begging the question means:','Asking a rhetorical question','Assuming in premises what you're trying to prove in conclusion','Avoiding the question','Providing too much evidence','B','Circular reasoning: conclusion is hidden in the premises.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which ASSUMPTION is needed for 'Since Zain passed MDCAT he must be hardworking'?','All people who pass MDCAT are hardworking','MDCAT is easy','Hardworking people always pass','Zain studied medicine','A','The argument assumes passing MDCAT requires hard work.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'An argument is SOUND if it is:','Valid only','Has true premises only','Both valid AND has true premises','Neither valid nor with true premises','C','A sound argument is valid AND has all true premises.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Which weakens 'Regular reading increases vocabulary'?','Reading is enjoyable','The high-vocabulary group reads more BUT already had rich home environments','All readers have large vocabularies','Books are educational','B','Alternative explanation (home environment) weakens the causal claim.','hard',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'Appeal to popularity (argumentum ad populum) is the fallacy of:','Citing an expert','Arguing something is true because many people believe it','Attacking someone personally','Drawing hasty conclusions','B','Something being popular/widely believed doesn't make it true.','medium',true),
((SELECT id FROM tests WHERE slug='hat'),(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat')),(SELECT id FROM topics WHERE slug='critical-reasoning' AND level_id=(SELECT id FROM levels WHERE level_no=3 AND test_id=(SELECT id FROM tests WHERE slug='hat'))),'What is the 'burden of proof' principle?','The defendant must always prove innocence','The person making a claim must provide evidence for it','Judges must always decide quickly','Evidence is never needed','B','Whoever makes a claim bears the responsibility to support it with evidence.','medium',true);
